   350→  private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
   351→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   352→      propertyName = cleanName(nameResolver.resolve(property));
   353→      objectPropertyNames.add(propertyName);
   354→
   355→      final String propName = propertyName;
   356→      RestrictionInfo.from(ce).ifPresent(info ->
   357→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   358→
   359→      if (ce.getFiller().isOWLClass()) {
   360→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
