    76→   */
    77→  public void addSchema(String shortName) {
    78→    schemaByRef.computeIfAbsent(shortName, s -> {
    79→      if (!computing.contains(s)) {
    80→        computing.add(s);
    81→        try {
    82→          OWLClass cls = manager.getOWLDataFactory().getOWLClass(IRI.create(defaultOntologyPrefixIRI + shortName));
