@Test
void testMultipleEnumValuesCreateStringSchemaWithEnumList() {
  TaxonomyPropertyMapper mapper = new TaxonomyPropertyMapper(
      context, "status", "Status description", "Status Label",
      List.of("Active", "Inactive", "Pending"), Collections.emptySet());

  Schema<?> schema = mapper.getTaxonomySchemaObject();

  assertInstanceOf(StringSchema.class, schema);
  StringSchema stringSchema = (StringSchema) schema;
  assertNotNull(stringSchema.getEnum());
  assertEquals(3, stringSchema.getEnum().size());
  assertTrue(stringSchema.getEnum().contains("Active"));
  assertTrue(stringSchema.getEnum().contains("Inactive"));
  assertTrue(stringSchema.getEnum().contains("Pending"));
}
```

